// RegisterInput adds every generated Input tool to the registry.
func RegisterInput(r *tools.Registry) {
	r.MustRegister(NewInputCancelDragging())
	r.MustRegister(NewInputDispatchDragEvent())
	r.MustRegister(NewInputDispatchKeyEvent())
	r.MustRegister(NewInputDispatchMouseEvent())
	r.MustRegister(NewInputDispatchTouchEvent())
	r.MustRegister(NewInputEmulateTouchFromMouseEvent())
	r.MustRegister(NewInputImeSetComposition())
	r.MustRegister(NewInputInsertText())
	r.MustRegister(NewInputSetIgnoreInputEvents())
	r.MustRegister(NewInputSetInterceptDrags())
	r.MustRegister(NewInputSynthesizePinchGesture())
	r.MustRegister(NewInputSynthesizeScrollGesture())
	r.MustRegister(NewInputSynthesizeTapGesture())
}
